import torch

def rebalance_experts(
    weight: torch.Tensor,
    num_replicas: int,
    num_groups: int,
    num_nodes: int,
    num_gpus: int,
) -> tuple[torch.Tensor, torch.Tensor, torch.Tensor]:
    num_layers, num_logical_experts = weight.shape  # [58, 256]
    weight = weight.float()

    # Step 1: Compute replica counts (must sum to 288 per layer)
    logcnt = torch.ones(num_layers, num_logical_experts, dtype=torch.int64)

    # Distribute remaining replicas proportionally to weights
    remaining = num_replicas - num_logical_experts
    if remaining > 0:
        normalized_weights = weight / (weight.sum(dim=1, keepdim=True) + 1e-8)
        extra_replicas = (normalized_weights * remaining).round().long()

        # Adjust for rounding errors
        current_sum = extra_replicas.sum(dim=1)
        diff = remaining - current_sum

        for layer in range(num_layers):
            if diff[layer] > 0:
                top_experts = torch.argsort(weight[layer], descending=True)
                for i in range(diff[layer]):
                    extra_replicas[layer, top_experts[i]] += 1
            elif diff[layer] < 0:
                bottom_experts = torch.argsort(weight[layer], descending=False)
                for i in range(-diff[layer]):
                    if extra_replicas[layer, bottom_experts[i]] > 0:
                        extra_replicas[layer, bottom_experts[i]] -= 1
                    else:
                        for j in range(num_logical_experts):
                            if extra_replicas[layer, top_experts[j]] > 0:
                                extra_replicas[layer, top_experts[j]] -= 1
                                break

        logcnt += extra_replicas
        logcnt = torch.clamp(logcnt, min=1)

    # Ensure final sum is exactly 288
    current_sum = logcnt.sum(dim=1)
    diff = num_replicas - current_sum
    for layer in range(num_layers):
        if diff[layer] > 0:
            top_experts = torch.argsort(weight[layer] / logcnt[layer].float(), descending=True)
            for i in range(diff[layer]):
                logcnt[layer, top_experts[i]] += 1
        elif diff[layer] < 0:
            sorted_idx = torch.argsort(weight[layer] / logcnt[layer].float(), descending=False)
            for i in range(-diff[layer]):
                for j in range(num_logical_experts):
                    expert_idx = sorted_idx[j]
                    if logcnt[layer, expert_idx] > 1:
                        logcnt[layer, expert_idx] -= 1
                        break

    # Step 2: Build phy2log [58, 288] from logcnt
    phy2log = torch.zeros(num_layers, num_replicas, dtype=torch.int64)
    for layer in range(num_layers):
        # Create repeated expert IDs according to logcnt
        expert_ids = torch.arange(num_logical_experts, dtype=torch.int64)
        repeats = logcnt[layer]
        repeated_expert_ids = torch.repeat_interleave(expert_ids, repeats)

        # Distribute across replicas in round-robin fashion to aid GPU balance
        sorted_indices = torch.argsort(weight[layer], descending=True)
        distributed_experts = []
        expert_counters = [0] * num_logical_experts

        # Fill using a greedy approach that ensures better GPU distribution
        for idx in range(num_replicas):
            # Find next expert with remaining replicas
            for log_id in sorted_indices:
                if expert_counters[log_id] < repeats[log_id]:
                    distributed_experts.append(log_id)
                    expert_counters[log_id] += 1
                    break

        phy2log[layer] = torch.tensor(distributed_experts, dtype=torch.int64)

    # Step 3: Build log2phy [58, 256, max_cnt] as inverse mapping
    max_cnt = logcnt.max().item()
    log2phy = torch.full((num_layers, num_logical_experts, max_cnt), -1, dtype=torch.int64)

    for layer in range(num_layers):
        # Create index mapping
        current_indices = torch.zeros(num_logical_experts, dtype=torch.int64)
        for phy_idx in range(num_replicas):
            log_id = phy2log[layer, phy_idx].item()
            idx_in_expert = current_indices[log_id].item()
            if idx_in_expert < max_cnt:
                log2phy[layer, log_id, idx_in_expert] = phy_idx
                current_indices[log_id] += 1

    return phy2log, log2phy, logcnt
